SELECT *, MATCH(title, content) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE) AS relevance FROM knowledge_entry WHERE deleted = 0 AND status = 'PUBLISHED'
AND category = #{category}
AND MATCH(title, content) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE) ORDER BY relevance DESC, view_count DESC, created_at DESC

SELECT *, 0 AS relevance FROM knowledge_entry WHERE deleted = 0 AND status = 'PUBLISHED' AND title LIKE CONCAT('%', #{keyword}, '%')
AND category = #{category}
ORDER BY view_count DESC, created_at DESC
